#include <stdio.h>

// Function prototypes
void getArray(int arr[], int *n);
void findMinMax(int arr[], int n, int *min, int *max);
void displayResult(int min, int max);

int main() {
    int arr[100], n, min, max;

    getArray(arr, &n);
    findMinMax(arr, n, &min, &max);
    displayResult(min, max);

    return 0;
}

void getArray(int arr[], int *n) {
    int i;
    printf("Enter number of elements: ");
    scanf("%d", n);
    printf("Enter %d elements: ", *n);
    for (i = 0; i < *n; i++) {
        scanf("%d", &arr[i]);
    }
}

void findMinMax(int arr[], int n, int *min, int *max) {
    int i;
    *min = arr[0];
    *max = arr[0];
    for (i = 1; i < n; i++) {
        if (arr[i] < *min) *min = arr[i];
        if (arr[i] > *max) *max = arr[i];
    }
}

void displayResult(int min, int max) {
    printf("Minimum: %d\nMaximum: %d\n", min, max);
}

/* File: calc.h - Header file with function declarations */
#ifndef CALC_H
#define CALC_H

int add(int a, int b);
int subtract(int a, int b);
int multiply(int a, int b);
float divide(int a, int b);

#endif

/* File: calc.c - Source file with implementations */
#include "calc.h"

int add(int a, int b) {
    return a + b;
}

int subtract(int a, int b) {
    return a - b;
}

int multiply(int a, int b) {
    return a * b;
}

float divide(int a, int b) {
    if (b != 0)
        return (float)a / b;
    return 0; /* Handle division by zero */
}

/* File: main.c - Main program using calculator module */
#include <stdio.h>
#include "calc.h"

int main() {
    int x = 10, y = 5;

    printf("Add: %d\n", add(x, y));
    printf("Subtract: %d\n", subtract(x, y));
    printf("Multiply: %d\n", multiply(x, y));
    printf("Divide: %.2f\n", divide(x, y));

    return 0;
}
